import{app}from"./firebase.min.js";import{getFirestore,doc,setDoc,updateDoc,getDoc,collection,addDoc,query,orderBy,limit,getDocs,serverTimestamp,deleteDoc,runTransaction}from"https://www.gstatic.com/firebasejs/12.1.0/firebase-firestore.js";const db=getFirestore(app);let currentChatDocId=null;export function getCurrentChatDocId(){return currentChatDocId}export function setCurrentChatDocId(t){currentChatDocId=t||null}export function resetCurrentChatDoc(){currentChatDocId=null}export function generateChatTitle(t=""){let e=t.trim().toLowerCase();if(!e)return"Conversation";e=e.replace(/please|can you|help me|i want|i need|i am|i'm|could you|would you|tell me|explain|show me/gi,""),e=e.trim();const r=e.split(/\s+/).filter(Boolean);if(r.length<3)return"Conversation";let a=r.slice(0,6).join(" ");return a=a.replace(/[^\w\s]/g,""),a.charAt(0).toUpperCase()+a.slice(1)}export async function saveChatToHistory(t,e,r,a=!1,o={}){try{if(!t)return null;const{mode:s="chat",metadata:n={},chatId:c=null}=o,i=collection(db,"history",t,"chats"),l=Date.now(),d={sender:"user",text:e||"",createdAt:l,mode:s,metadata:n},u={sender:"ai",text:r||"",createdAt:l,mode:s,metadata:n};if(a||!c){const t=generateChatTitle(e);return(await addDoc(i,{title:t,messages:[d,u],createdAt:serverTimestamp(),updatedAt:serverTimestamp(),lastMode:s})).id}const h=doc(db,"history",t,"chats",c);return await runTransaction(db,async t=>{const r=await t.get(h);if(!r.exists())return t.set(h,{title:generateChatTitle(e),messages:[d,u],createdAt:serverTimestamp(),updatedAt:serverTimestamp(),lastMode:s}),c;const a=r.data(),o=Array.isArray(a.messages)?a.messages:[],n=a.title,i=!n||"Conversation"===n||n.trim().length<10;return t.update(h,{messages:[...o,d,u],updatedAt:serverTimestamp(),lastMode:s,...i&&{title:generateChatTitle(d.text)}}),c})}catch(t){return console.error("🔥 Error saving chat:",t),null}}export async function getLatestChat(t){try{if(!t)return null;const e=collection(db,"history",t,"chats"),r=query(e,orderBy("createdAt","desc"),limit(1)),a=await getDocs(r);if(!a.empty){const t=a.docs[0];return currentChatDocId=t.id,{chatId:t.id,messages:t.data().messages||[]}}return currentChatDocId=null,null}catch(t){return console.error("🔥 Error retrieving latest chat:",t),currentChatDocId=null,null}}export async function saveFullChatSession(t,e){if(t&&e&&0!==e.length)try{const r=e.find(t=>"user"===t.sender)?.text||"Conversation",a=r.length>30?r.slice(0,30)+"...":r,o=doc(collection(db,"history",t,"sessions"));await setDoc(o,{title:a,messages:e,createdAt:serverTimestamp()}),console.log("✅ Chat session saved:",a)}catch(t){console.error("❌ Failed to save full chat session:",t)}}export async function getAllChats(t){try{if(!t)return console.warn("⚠️ No userId provided to getAllChats()"),[];const e=collection(db,"history",t,"chats"),r=query(e,orderBy("createdAt","desc")),a=await getDocs(r);return a.docs.map(t=>({id:t.id,...t.data()}))}catch(t){return console.error("🔥 Error fetching chats:",t),[]}}export async function getChatById(t,e){if(!t||!e)return console.error("❌ Missing userUID or chatId"),null;try{const r=doc(db,"history",t,"chats",e),a=await getDoc(r);if(!a.exists())return console.warn("⚠️ No such chat:",e),null;const o=a.data(),s=(o.messages||[]).map(t=>({role:"user"===t.sender?"user":"ai",content:t.text||"",mode:t.mode||"chat",metadata:t.metadata||{},createdAt:"number"==typeof t.createdAt?t.createdAt:t.createdAt?.toMillis?t.createdAt.toMillis():null}));return{id:e,...o,messages:s}}catch(t){return console.error("🔥 Error fetching chat by ID:",t),null}}export async function deleteChatHistory(t,e){if(t&&e)try{const r=doc(db,"history",t,"chats",e);await deleteDoc(r),console.log("🗑 Chat deleted:",e)}catch(t){console.error("❌ Failed to delete chat:",t)}}export async function createNewChatDoc(t,e="New Conversation"){try{if(!t)return null;const r=collection(db,"history",t,"chats"),a=await addDoc(r,{title:e,messages:[],createdAt:serverTimestamp(),updatedAt:serverTimestamp(),lastMode:"chat"});return currentChatDocId=a.id,a.id}catch(t){return console.error("🔥 Error creating new chat doc:",t),null}}